const rows = $input.all(); // gets all rows from previous node

let message = "";
let counter = 0;
for (const row of rows) {
  const contents = row.json.Contents;
  if (counter%2 == 1){
    message += `user:\n ${contents}\n`;
  }
  else{
     message += `admin response:\n ${contents}\n`;
  }

  counter += 1;
}

return [
  {
    json: {
      textBody: message,
      replyCount: counter
    }
  }
];

const previous = $('ReformatSQLOutput').first().json.textBody
const latestEmail = $('Gmail Trigger').first().json.text

const updatedMessage = previous + `user:\n ${latestEmail}\n`;

return [
  {
    json: {
      textBody: updatedMessage
    }
  }
];

